SELECT list_name
FROM species_lists
WHERE public = 1;

SELECT COUNT(*) AS public_list_count
FROM species_lists
WHERE public = 1;

SELECT owner_id, COUNT(list_id) AS total_lists
FROM species_lists
GROUP BY owner_id;

SELECT list_name, item_count 
FROM species_lists 
ORDER BY item_count DESC;

SELECT list_name, item_count
FROM species_lists
WHERE item_count = (SELECT MAX(item_count) FROM species_lists);

SELECT type_name 
FROM list_types 
WHERE is_protected = 1;

SELECT owner_name
FROM owners
WHERE owner_id IN (
    SELECT DISTINCT owner_id
    FROM species_lists
);
